#include <stdio.h>
#include <stdlib.h>

#define MAXN 105
#define MAXE 210

int head[MAXN];
int to[MAXE];
int nxt[MAXE];
int ecnt;
int col[MAXN];
int q[MAXN];

void addEdge(int u,int v){
    to[ecnt]=v; nxt[ecnt]=head[u]; head[u]=ecnt++;
    to[ecnt]=u; nxt[ecnt]=head[v]; head[v]=ecnt++;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        for(int i=1;i<=N;i++) head[i]=-1, col[i]=-1;
        ecnt=0;
        for(int i=0;i<N-1;i++){
            int u,v; scanf("%d %d",&u,&v);
            addEdge(u,v);
        }
        int front=0, back=0;
        q[back++]=1; col[1]=0;
        while(front<back){
            int u=q[front++];
            for(int e=head[u]; e!=-1; e=nxt[e]){
                int v=to[e];
                if(col[v]==-1){
                    col[v]=col[u]^1;
                    q[back++]=v;
                }
            }
        }
        for(int i=1;i<=N;i++){
            int val = (col[i]==0)?1:2;
            printf("%d",val);
            if(i<N) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

