#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        g = [[] for _ in range(N+1)]
        for _ in range(N-1):
            u = int(next(it)); v = int(next(it))
            g[u].append(v); g[v].append(u)
        col = [-1]*(N+1)
        from collections import deque
        q = deque([1])
        col[1] = 0
        while q:
            u = q.popleft()
            for v in g[u]:
                if col[v] == -1:
                    col[v] = col[u]^1
                    q.append(v)
        vals = ['1' if col[i]==0 else '2' for i in range(1,N+1)]
        out_lines.append(' '.join(vals))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

