    g[v].push(u);
  }
  const col = new Array(N + 1).fill(-1);
  const queue = [];
  queue.push(1);
  col[1] = 0;
  while (queue.length) {
    const u = queue.shift();
    for (const v of g[u]) {
      if (col[v] === -1) {
        col[v] = col[u] ^ 1;
        queue.push(v);
      }
    }
  }
  const line = [];
  for (let i = 1; i <= N; i++) {
    line.push(col[i] === 0 ? '1' : '2');
  }
  output.push(line.join(' '));
}
